alter table public.mq_cities add column if not exists voivodeship text;

on conflict(slug) do update set name=excluded.name,voivodeship=excluded.voivodeship,center_lat=excluded.center_lat,center_lon=excluded.center_lon,active_missions=10,required_missions=5;

select c.id,v.slug,v.title||' - '||c.name,v.description||' w miescie '||c.name,v.kind,v.target,c.center_lat+v.lat_offset,c.center_lon+v.lon_offset,v.radius,v.photo,v.motorcycle,v.xp
from public.mq_cities c cross join (values
('serce-miasta','Serce miasta','Dotrzyj do historycznego centrum i odkryj jego charakter','explore','centrum',0.000,0.000,1800,false,false,300),
('miejski-kadr','Pocztowka z trasy','Zrob wyrazne zdjecie charakterystycznego miejsca','photo','punkt miejski',0.004,0.003,2200,true,false,450),
('motocyklowy-kadr','Maszyna i miasto','Uwiecznij motocykl podczas miejskiej wyprawy','motoshot','centrum',-0.003,0.004,2400,true,true,650),
('zielony-przystanek','Zielony przystanek','Odszukaj park, bulwar lub spokojny punkt odpoczynku','poi','teren rekreacyjny',0.006,-0.004,2500,false,false,350),
('petla-odkrywcy','Petla odkrywcy','Przejedz przez przeciwlegle czesci miasta i zakoncz petle','ride','trasa miejska',-0.006,-0.005,2800,false,true,550)
) as v(slug,title,description,kind,target,lat_offset,lon_offset,radius,photo,motorcycle,xp)
on conflict(city_id,slug) do update set title=excluded.title,description=excluded.description,target_lat=excluded.target_lat,target_lon=excluded.target_lon,radius_m=excluded.radius_m,xp=excluded.xp;
